//! OpenCV parity tests — validates our filters against OpenCV reference output.
//!
//! Reference fixtures generated by OpenCV 4.13.0 (cv2) and stored in
//! tests/fixtures/opencv/. Each test loads input + reference output,
//! runs our implementation, and checks MAE is within tolerance.

use rasmcore_image::domain::filters;
use rasmcore_image::domain::types::{ColorSpace, ImageInfo, PixelFormat};

fn load_fixture(name: &str) -> Vec<u8> {
    let path = format!(
        "{}/tests/fixtures/opencv/{name}",
        env!("CARGO_MANIFEST_DIR")
    );
    std::fs::read(&path).unwrap_or_else(|e| panic!("fixture {path}: {e}"))
}

fn mae(a: &[u8], b: &[u8]) -> f64 {
    assert_eq!(a.len(), b.len());
    a.iter()
        .zip(b.iter())
        .map(|(&x, &y)| (x as f64 - y as f64).abs())
        .sum::<f64>()
        / a.len() as f64
}

fn psnr(a: &[u8], b: &[u8]) -> f64 {
    let mse: f64 = a
        .iter()
        .zip(b.iter())
        .map(|(&x, &y)| (x as f64 - y as f64).powi(2))
        .sum::<f64>()
        / a.len() as f64;
    if mse == 0.0 {
        return 99.0;
    }
    10.0 * (255.0_f64.powi(2) / mse).log10()
}

#[test]
fn clahe_matches_opencv() {
    let input = load_fixture("low_contrast_64x64.raw");
    let reference = load_fixture("clahe_64x64_clip2_grid8.raw");

    let info = ImageInfo {
        width: 64,
        height: 64,
        format: PixelFormat::Gray8,
        color_space: ColorSpace::Srgb,
    };

    let ours = filters::clahe(&input, &info, 2.0, 8).unwrap();

    let error = mae(&ours, &reference);
    let quality = psnr(&ours, &reference);

    eprintln!(
        "CLAHE vs OpenCV: MAE={error:.2}, PSNR={quality:.1}dB, ours_range=[{},{}], ref_range=[{},{}]",
        ours.iter().min().unwrap(),
        ours.iter().max().unwrap(),
        reference.iter().min().unwrap(),
        reference.iter().max().unwrap(),
    );

    // CLAHE implementations differ in tile boundary handling and interpolation.
    // Accept MAE < 15 (generous) — the key is that both expand the dynamic range similarly.
    assert!(
        error < 15.0,
        "CLAHE MAE vs OpenCV {error:.2} > 15.0 — implementation diverges"
    );
    assert!(
        quality > 20.0,
        "CLAHE PSNR vs OpenCV {quality:.1}dB < 20dB — implementation diverges"
    );

    // Both should significantly expand the range (input is 100-155)
    let our_range =
        *ours.iter().max().unwrap() as i32 - *ours.iter().min().unwrap() as i32;
    assert!(
        our_range > 100,
        "CLAHE should expand range significantly, got {our_range}"
    );
}

#[test]
fn bilateral_matches_opencv() {
    let input = load_fixture("gradient_64x64_gray.raw");
    let reference = load_fixture("bilateral_64x64_d9_sc75_ss75.raw");

    let info = ImageInfo {
        width: 64,
        height: 64,
        format: PixelFormat::Gray8,
        color_space: ColorSpace::Srgb,
    };

    let ours = filters::bilateral(&input, &info, 9, 75.0, 75.0).unwrap();

    let error = mae(&ours, &reference);
    let quality = psnr(&ours, &reference);

    eprintln!("Bilateral vs OpenCV: MAE={error:.2}, PSNR={quality:.1}dB");

    // Bilateral: float arithmetic differs between implementations.
    // MAE < 1.0 and PSNR > 45dB confirms algorithmic correctness.
    // Max per-pixel error ≤ 4 at corners (boundary reflection rounding).
    assert!(
        error < 1.0,
        "Bilateral MAE vs OpenCV {error:.2} > 1.0 — implementation diverges"
    );
    assert!(
        quality > 45.0,
        "Bilateral PSNR vs OpenCV {quality:.1}dB < 45dB — implementation diverges"
    );
}

#[test]
fn bilateral_max_error_analysis() {
    let input = load_fixture("gradient_64x64_gray.raw");
    let reference = load_fixture("bilateral_64x64_d9_sc75_ss75.raw");

    let info = ImageInfo {
        width: 64, height: 64,
        format: PixelFormat::Gray8,
        color_space: ColorSpace::Srgb,
    };

    let ours = filters::bilateral(&input, &info, 9, 75.0, 75.0).unwrap();

    let mut max_diff = 0i32;
    let mut max_pos = (0, 0);
    let mut error_histogram = [0u32; 10];
    for y in 0..64 {
        for x in 0..64 {
            let i = y * 64 + x;
            let diff = (ours[i] as i32 - reference[i] as i32).abs();
            if diff > max_diff {
                max_diff = diff;
                max_pos = (x, y);
            }
            if (diff as usize) < error_histogram.len() {
                error_histogram[diff as usize] += 1;
            }
        }
    }
    eprintln!("Bilateral max error: {max_diff} at ({}, {})", max_pos.0, max_pos.1);
    eprintln!("Error histogram: 0={}, 1={}, 2={}, 3+={}", 
        error_histogram[0], error_histogram[1], error_histogram[2],
        error_histogram[3..].iter().sum::<u32>());
    
    // Max error ≤ 4 at corner pixels (float precision + boundary reflection)
    // 69% pixels exact, 12% off-by-1, 14% off-by-2, 5% off-by-3/4
    assert!(max_diff <= 4, "bilateral max error {max_diff} > 4");
}
